import secrets

def getSessionID():
    '''
    Return a random and unique session ID.
    '''
    return secrets.token_urlsafe(32)

import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['GET', 'POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Get YAML data from the request body (POST) or from a 'data' query parameter (GET)
    yaml_text = request.get_data(as_text=True) if request.method == 'POST' else request.args.get('data', '')

    if not yaml_text:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # safe_load only recognizes standard YAML tags and prevents the execution of arbitrary Python objects
        parsed_data = yaml.safe_load(yaml_text)
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
